import {events} from './events.js';
import {getConfig,setConfig,getMainEditor,getCurrentEditor,setCurrentEditor} from './states.js';
import {unsetSel} from './editmode.js';
import {initKey,textToButton,showGuide,renderModifierState,modifiers} from '@acepad/keypad';
import {edit,selectKeyDevice,input} from "./editorcore.js";

export function getInstance(){
    return {
        editor: getCurrentEditor(),
        events,
        edit,selectKeyDevice,input,
        getConfig,setConfig,
        getMainEditor,
        getCurrentEditor,setCurrentEditor,
        unsetSel,
        setModifier:modifiers.setModifier,
        renderModifierState,
        initKey,textToButton,showGuide,
    };
}
